	--sky-color-background-action-primary-active: var(--bb-color-blue-500) !important;
	--sky-color-background-action-primary-focus: var(--bb-color-blue-500) !important;
	--sky-color-border-action-primary-base: var(--bb-color-blue-500) !important;
	--sky-color-border-action-primary-hover: var(--bb-color-blue-500) !important;
	--sky-color-border-action-primary-active: var(--bb-color-blue-500) !important;
	--sky-color-border-action-primary-focus: var(--bb-color-blue-500) !important;
}

/* Default override lane: gray neutrals. */
body.sky-theme-modern.sky-theme-brand-base.sky-theme-mode-dark {
	--sky-color-background-page: var(--local-exp-gray-1050) !important;
	--sky-color-background-container-base: var(--local-exp-gray-975) !important;
	--sky-color-background-container-dimmed: var(--local-exp-gray-950) !important;
	--sky-color-background-container-backdrop: var(--local-exp-gray-925) !important;
	--sky-color-background-disabled: var(--local-exp-gray-950) !important;
	--local-exp-input-border-base: var(--local-exp-gray-950) !important;
	--sky-color-border-container-border: var(--local-exp-gray-1000) !important;

	/* Structural border hierarchy (gray lane):
	   page divider > elevation outline > container/soft separators > disabled */
	--sky-color-border-divider: var(--local-exp-gray-925) !important;
	--sky-color-border-elevation: var(--local-exp-gray-925) !important;
	--sky-color-border-container-base: var(--local-exp-gray-1000) !important;
	--sky-color-border-separator-row: var(--local-exp-gray-950) !important;
	--sky-color-border-separator-dark: var(--local-exp-gray-950) !important;
	--sky-color-border-separator-light: var(--local-exp-gray-975) !important;
	--sky-color-border-disabled: var(--local-exp-gray-975) !important;
}

/* Optional lane switch for testing: add `local-exp-neutral-slate` on body. */
body.sky-theme-modern.sky-theme-brand-base.sky-theme-mode-dark.local-exp-neutral-slate {
	--sky-color-background-page: var(--local-exp-gray-1050) !important;
	--sky-color-background-container-base: var(--local-exp-gray-975) !important;
	--sky-color-background-container-dimmed: var(--local-exp-gray-950) !important;
	--sky-color-background-container-backdrop: var(--local-exp-gray-925) !important;
	--sky-color-background-disabled: var(--local-exp-slate-950) !important;
	--local-exp-input-border-base: var(--local-exp-slate-950) !important;
	--sky-color-border-container-border: var(--local-exp-gray-1000) !important;

	/* Structural border hierarchy (gray lane). */
	--sky-color-border-divider: var(--local-exp-gray-925) !important;
	--sky-color-border-elevation: var(--local-exp-gray-925) !important;
	--sky-color-border-container-base: var(--local-exp-gray-1000) !important;
	--sky-color-border-separator-row: var(--local-exp-gray-950) !important;
	--sky-color-border-separator-dark: var(--local-exp-gray-950) !important;
	--sky-color-border-separator-light: var(--local-exp-gray-975) !important;
	--sky-color-border-disabled: var(--local-exp-gray-975) !important;
