	border: 1px solid transparent !important;
	border-radius: var(--sky-theme-border-radius-s, 4px) !important;
	background-color: var(--sky-color-background-container-base) !important;
	position: relative;
}

/* Override utility border token class with a vertical slate gradient. */
body.sky-theme-modern.sky-theme-brand-base.sky-theme-mode-dark .sky-theme-border-container-default {
	border: 1px solid transparent !important;
	border-radius: var(--sky-theme-border-radius-s, 4px) !important;
	background-color: var(--sky-color-background-container-base) !important;
	position: relative;
}

body.sky-theme-modern.sky-theme-brand-base.sky-theme-mode-dark .swatch {
	border: 1px solid transparent !important;
	background-color: var(--sky-color-background-page) !important;
	position: relative;
}

body.sky-theme-modern.sky-theme-brand-base.sky-theme-mode-dark .sky-box.sky-elevation-1-bordered::before,
body.sky-theme-modern.sky-theme-brand-base.sky-theme-mode-dark .sky-theme-border-container-default::before,
body.sky-theme-modern.sky-theme-brand-base.sky-theme-mode-dark .swatch::before {
	content: '';
	position: absolute;
	inset: 0;
	border-radius: inherit;
	padding: 1px;
	background: linear-gradient(
		to top,
		var(--bb-color-gray-800),
		var(--bb-color-gray-850)
	);
	-webkit-mask: linear-gradient(#000 0 0) content-box, linear-gradient(#000 0 0);
	-webkit-mask-composite: xor;
	mask: linear-gradient(#000 0 0) content-box, linear-gradient(#000 0 0);
	mask-composite: exclude;
	pointer-events: none;
}

/* Phase B – surface-relative experiment (do not ship)
   Mechanical model only: one fixed lift delta applied from immediate surface.
   No per-surface or per-component tuning. */
body.sky-theme-modern.sky-theme-brand-base.sky-theme-mode-dark {
	--local-exp-current-surface: var(--sky-color-background-page);
	--local-exp-input-lift-surface-weight: 84%;
	--local-exp-input-lift-white-weight: 16%;
}

/* Detect surface context from existing SKY UX structure/classes. */
body.sky-theme-modern.sky-theme-brand-base.sky-theme-mode-dark :where(
	.sky-box,
	.sky-theme-color-background-container-default,
	.sky-theme-background-container-default,
	[data-sky-surface='container-base']
) {
	--local-exp-current-surface: var(--sky-color-background-container-base);
}

body.sky-theme-modern.sky-theme-brand-base.sky-theme-mode-dark :where(
	.sky-theme-color-background-container-dimmed,
	.sky-theme-background-container-dimmed,
	.sky-background-container-dimmed,
	[data-sky-surface='container-dimmed']
) {
	--local-exp-current-surface: var(--sky-color-background-container-dimmed);
}

body.sky-theme-modern.sky-theme-brand-base.sky-theme-mode-dark :where(
