	.sky-theme-background-container-backdrop,
	.sky-background-container-backdrop,
	[data-sky-surface='container-backdrop']
) {
	--local-exp-current-surface: var(--sky-color-background-container-backdrop);
}

/* Phase B – borders/dividers layered with the same surface model.
   Dividers are computed from each container's immediate surface.
   Soft divider remains one fixed step weaker than divider in the same layer. */
body.sky-theme-modern.sky-theme-brand-base.sky-theme-mode-dark {
	--local-exp-border-surface: var(--sky-color-background-page);
	--local-exp-divider-white-strength: 24%;
	--local-exp-divider-soft-step: 4%;
	--local-exp-container-outline-step: 2%;
	--local-exp-input-border-step: 6%;

	--sky-color-border-divider: color-mix(
		in oklab,
		var(--local-exp-border-surface) calc(100% - var(--local-exp-divider-white-strength)),
		white var(--local-exp-divider-white-strength)
	) !important;
	--sky-color-border-separator-row: color-mix(
		in oklab,
		var(--local-exp-border-surface) calc(100% - (var(--local-exp-divider-white-strength) - var(--local-exp-divider-soft-step))),
		white calc(var(--local-exp-divider-white-strength) - var(--local-exp-divider-soft-step))
	) !important;
	--sky-color-border-container-base: color-mix(
		in oklab,
		var(--local-exp-border-surface) calc(100% - (var(--local-exp-divider-white-strength) + var(--local-exp-container-outline-step))),
		white calc(var(--local-exp-divider-white-strength) + var(--local-exp-container-outline-step))
	) !important;
	--sky-color-border-elevation: color-mix(
		in oklab,
		var(--local-exp-border-surface) calc(100% - (var(--local-exp-divider-white-strength) + var(--local-exp-container-outline-step))),
		white calc(var(--local-exp-divider-white-strength) + var(--local-exp-container-outline-step))
	) !important;
	--sky-color-border-input-base: color-mix(
		in oklab,
		var(--local-exp-border-surface) calc(100% - (var(--local-exp-divider-white-strength) + var(--local-exp-input-border-step))),
		white calc(var(--local-exp-divider-white-strength) + var(--local-exp-input-border-step))
	) !important;
	--local-exp-input-border-base: var(--sky-color-border-input-base) !important;
}

body.sky-theme-modern.sky-theme-brand-base.sky-theme-mode-dark :where(
