import { buildStylesPlugin } from './plugins/build-styles-plugin.mjs';
import {
  buildAssetsManifestPlugin,
  buildStyleDictionaryPlugin,
  preparePackagePlugin,
} from '@blackbaud/skyux-branding-builder';
import { tokenConfig } from './src/tokens/token-config.mts';

export default ({ mode }) => {
  const viteEnv = loadEnv(mode, process.cwd());

  return defineConfig({
    build: {
      lib: {
        entry: path.resolve(__dirname, 'src/dev/main.ts'),
        name: 'SkyuxDesignTokens',
        fileName() {
          return `bundles/design-tokens.global.min.js`;
        },
        formats: ['es'],
      },
    },
    preview: {
      open: true,
    },
    server: {
      https: viteEnv.VITE_DEV_CERT
        ? {
            cert: viteEnv.VITE_DEV_CERT,
            key: viteEnv.VITE_DEV_KEY,
          }
        : undefined,
      open: true,
      cors: {
        origin: '*',
        methods: ['GET', 'POST', 'PUT', 'DELETE'],
        allowedHeaders: ['Content-Type', 'Authorization'],
      },
    },
    test: {
      name: 'Design Tokens',
      environment: 'node',
      root: path.resolve(__dirname),
      mockReset: true,
    },
    plugins: [
      buildStylesPlugin(),
      buildStyleDictionaryPlugin(tokenConfig),
      buildAssetsManifestPlugin(tokenConfig.projectName),
      preparePackagePlugin(__dirname),
    ],
  });
};
"}]}]

[{"role":"tool","parts":[{"type":"tool_call_response","id":"call_gZIqKwelHt8uMGLosIfwS2zD","response":"<!doctype html>
<html lang="en">
  <head>
    <meta charset="UTF-8" />
    <meta name="viewport" content="width=device-width, initial-scale=1.0" />
    <title>Vite + TS</title>
  </head>
  <body>
    <div id="app"></div>
    <script type="module" src="/src/dev/main.ts"></script>
    <script type="module">
      const urlParams = new URLSearchParams(location.search);
      const localPreviewMode = urlParams.get('local-preview');
      const localPreview =
        localPreviewMode === 'palette' ||
        localPreviewMode === 'layers' ||
        localPreviewMode === 'sandbox';

      if (localPreview) {
        const head = document.head;
        document.body.dataset.localBuild = '5176-preview';

        [
          'dist/bundles/base.css',
          'dist/bundles/blackbaud.css',
          'src/dev/tokens.css',
          'src/dev/extra-styles.css',
        ].forEach((href) => {
          const link = document.createElement('link');
          link.rel = 'stylesheet';
          link.href = `/${href}`;
          head.appendChild(link);
        });

        if (localPreviewMode === 'layers') {
          document.body.dataset.layering = 'current';
          document.body.classList.add(
            'sky-theme-modern',
            'sky-theme-brand-base',
            'sky-theme-brand-blackbaud',
            'sky-theme-mode-dark',
            'local-preview-layering',
          );

          const app = document.getElementById('app');

          if (app) {
            app.innerHTML = `
              <main class="local-layer-sandbox local-layer-sandbox-strict local-layer-demo">
                <header class="local-layer-controls" data-sky-layer="00">
                  <h1 class="local-layer-model-title">SKY UX Dark Surface Layering Sandbox</h1>
                  <p class="local-layer-model-copy">Static demo for inspecting background, border, divider, and field behavior across L0-L3.</p>
                  <p class="local-layer-model-copy">Experimental override hooks: <strong>--local-demo-l1-bg</strong>, <strong>--local-demo-l2-bg</strong>, <strong>--local-demo-l3-bg</strong>, <strong>--local-demo-border</strong>, <strong>--local-demo-divider</strong>, <strong>--local-demo-input-bg</strong>.</p>
                </header>

                <section class="local-layer-surface local-layer-l0" data-sky-layer="00" aria-label="Layer 0 page surface">
                  <span class="local-layer-chip">L0 Page</span>
                  <h2>L0: Page Surface</h2>
                  <p>Base dark canvas representing page-level context and defaults.</p>
                  <div class="local-layer-divider" role="separator"></div>
                  <div class="sky-input-box">
                    <input aria-label="L0 page input" placeholder="Input on L0 page" />
                  </div>
                  <p><a href="#">Page-level link</a></p>

                  <section class="local-layer-surface local-layer-l1" data-sky-layer="01" aria-label="Layer 1 container surface">
                    <span class="local-layer-chip">L1 Container</span>
                    <h3>L1: Container Surface</h3>
                    <p>Primary container surface with nested content for intra-layer contrast checks.</p>
                    <div class="local-layer-divider" role="separator"></div>
                    <div class="sky-input-box">
                      <input aria-label="L1 container input" placeholder="Input on L1 container" />
                    </div>
                    <p><a href="#">Container link</a></p>

                    <article class="local-layer-surface local-layer-l1-nested" data-sky-layer="01" aria-label="Layer 1 nested content">
                      <span class="local-layer-chip">L1 Nested</span>
                      <h4>L1: Nested Content</h4>
                      <p>Nested block on the same layer for divider and border subtlety checks.</p>
                      <div class="local-layer-divider" role="separator"></div>
                      <div class="sky-input-box">
                        <input aria-label="L1 nested input" placeholder="Input in L1 nested content" />
                      </div>
                      <p><a href="#">Nested-content link</a></p>
                    </article>

                    <aside class="local-layer-surface local-layer-l2" data-sky-layer="02" aria-label="Layer 2 overlay surface">
                      <span class="local-layer-chip">L2 Overlay</span>
                      <h4>L2: Floating Overlay</h4>
                      <p>Overlay surface positioned over L1 for hierarchy and elevation validation.</p>
                      <div class="local-layer-divider" role="separator"></div>
                      <div class="sky-input-box">
                        <input aria-label="L2 overlay input" placeholder="Input on L2 overlay" />
                      </div>
                      <p><a href="#">Overlay link</a></p>
                    </aside>
                  </section>
                </section>

                <section class="local-layer-surface local-layer-l3" data-sky-layer="03" aria-label="Layer 3 modal surface">
                  <span class="local-layer-chip">L3 Modal</span>
                  <h3>L3: Modal Surface</h3>
                  <p>Top-layer modal treatment for highest-priority surface testing.</p>
                  <div class="local-layer-divider" role="separator"></div>
                  <div class="sky-input-box">
                    <input aria-label="L3 modal input" placeholder="Input on L3 modal" />
                  </div>
                  <p><a href="#">Modal link</a></p>
                </section>
              </main>`;
          }
        }
      } else {
        const launchParam = import.meta.env.VITE_LAUNCH_QSPARAM;
        let launchUrl = import.meta.env.VITE_LAUNCH_URL;

        if (!launchUrl.endsWith('/')) {
          launchUrl += '/';
        }

        const localUrl = new URL(import.meta.url);

        const configEncoded = btoa(
          JSON.stringify({
            localUrl: localUrl.origin,
            scripts: [
              {
                name: '@vite/client',
                scriptType: 'module',
              },
              {
                name: 'src/dev/main.ts',
                scriptType: 'module',
              },
            ],
            stylesheets: [
              {
                name: 'src/dev/tokens.css',
              },
              {
                name: 'src/dev/extra-styles.css',
              },
            ],
          }),
        );

        location.replace(
          `${launchUrl}?${launchParam}=${encodeURIComponent(configEncoded)}`,
        );
      }
    </script>
  </body>
</html>
"}]}]

