[{"role":"tool","parts":[{"type":"tool_call_response","id":"call_xrwWsEssPYUVrhiL3PDhQEUT","response":"body.sky-theme-modern.sky-theme-brand-base.sky-theme-mode-dark {
	/* Experimental neutral steps from Phase A (gray + slate lanes). */
	--local-exp-gray-1050: #1a1e24;
	--local-exp-gray-1000: #1e2229;
	--local-exp-gray-925: #232930;
	--local-exp-gray-975: #20242b;
	--local-exp-gray-950: #21262e;

	--local-exp-slate-1050: #171e2b;
	--local-exp-slate-1125: #131822;
	--local-exp-slate-1150: #11161e;
	--local-exp-slate-1175: #0f131a;
	--local-exp-slate-850: #2a384f;
	--local-exp-slate-925: #1f293b;
	--local-exp-slate-975: #1c2434;
	--local-exp-slate-950: #1d2738;

	/* Force action reference tokens to Blue-500 in dark previews. */
	--sky-color-text-action: var(--bb-color-blue-500) !important;
	--sky-theme-color-text-action: var(--bb-color-blue-500) !important;
	--sky-color-icon-action: var(--bb-color-blue-500) !important;
	--sky-theme-color-icon-action: var(--bb-color-blue-500) !important;
	--sky-color-background-action-primary-base: var(--bb-color-blue-500) !important;
	--sky-color-background-action-primary-hover: var(--bb-color-blue-500) !important;
	--sky-color-background-action-primary-active: var(--bb-color-blue-500) !important;
	--sky-color-background-action-primary-focus: var(--bb-color-blue-500) !important;
	--sky-color-border-action-primary-base: var(--bb-color-blue-500) !important;
	--sky-color-border-action-primary-hover: var(--bb-color-blue-500) !important;
	--sky-color-border-action-primary-active: var(--bb-color-blue-500) !important;
	--sky-color-border-action-primary-focus: var(--bb-color-blue-500) !important;
}

/* Default override lane: gray neutrals. */
body.sky-theme-modern.sky-theme-brand-base.sky-theme-mode-dark {
	--sky-color-background-page: var(--local-exp-gray-1050) !important;
	--sky-color-background-container-base: var(--local-exp-gray-975) !important;
	--sky-color-background-container-dimmed: var(--local-exp-gray-950) !important;
	--sky-color-background-container-backdrop: var(--local-exp-gray-925) !important;
	--sky-color-background-disabled: var(--local-exp-gray-950) !important;
	--local-exp-input-border-base: var(--local-exp-gray-950) !important;
	--sky-color-border-container-border: var(--local-exp-gray-1000) !important;

	/* Structural border hierarchy (gray lane):
	   page divider > elevation outline > container/soft separators > disabled */
	--sky-color-border-divider: var(--local-exp-gray-925) !important;
	--sky-color-border-elevation: var(--local-exp-gray-925) !important;
	--sky-color-border-container-base: var(--local-exp-gray-1000) !important;
	--sky-color-border-separator-row: var(--local-exp-gray-950) !important;
	--sky-color-border-separator-dark: var(--local-exp-gray-950) !important;
	--sky-color-border-separator-light: var(--local-exp-gray-975) !important;
	--sky-color-border-disabled: var(--local-exp-gray-975) !important;
}

/* Optional lane switch for testing: add `local-exp-neutral-slate` on body. */
body.sky-theme-modern.sky-theme-brand-base.sky-theme-mode-dark.local-exp-neutral-slate {
	--sky-color-background-page: var(--local-exp-gray-1050) !important;
	--sky-color-background-container-base: var(--local-exp-gray-975) !important;
	--sky-color-background-container-dimmed: var(--local-exp-gray-950) !important;
	--sky-color-background-container-backdrop: var(--local-exp-gray-925) !important;
	--sky-color-background-disabled: var(--local-exp-slate-950) !important;
	--local-exp-input-border-base: var(--local-exp-slate-950) !important;
	--sky-color-border-container-border: var(--local-exp-gray-1000) !important;

	/* Structural border hierarchy (gray lane). */
	--sky-color-border-divider: var(--local-exp-gray-925) !important;
	--sky-color-border-elevation: var(--local-exp-gray-925) !important;
	--sky-color-border-container-base: var(--local-exp-gray-1000) !important;
	--sky-color-border-separator-row: var(--local-exp-gray-950) !important;
	--sky-color-border-separator-dark: var(--local-exp-gray-950) !important;
	--sky-color-border-separator-light: var(--local-exp-gray-975) !important;
	--sky-color-border-disabled: var(--local-exp-gray-975) !important;
}

/* Force visibility on host-provided legacy classes used by the demo app. */
body.sky-theme-modern.sky-theme-brand-base.sky-theme-mode-dark .sky-box {
	border-color: var(--sky-color-border-container-base) !important;
}

body.sky-theme-modern.sky-theme-brand-base.sky-theme-mode-dark .sky-elevation-1-bordered {
	border: 1px solid var(--sky-color-border-elevation) !important;
}

body.sky-theme-modern.sky-theme-brand-base.sky-theme-mode-dark .sky-box.sky-elevation-1-bordered {
	border: 1px solid transparent !important;
	border-radius: var(--sky-theme-border-radius-s, 4px) !important;
	background-color: var(--sky-color-background-container-base) !important;
	position: relative;
}

/* Override utility border token class with a vertical slate gradient. */
body.sky-theme-modern.sky-theme-brand-base.sky-theme-mode-dark .sky-theme-border-container-default {
	border: 1px solid transparent !important;
	border-radius: var(--sky-theme-border-radius-s, 4px) !important;
	background-color: var(--sky-color-background-container-base) !important;
	position: relative;
}

body.sky-theme-modern.sky-theme-brand-base.sky-theme-mode-dark .swatch {
	border: 1px solid transparent !important;
	background-color: var(--sky-color-background-page) !important;
	position: relative;
}

body.sky-theme-modern.sky-theme-brand-base.sky-theme-mode-dark .sky-box.sky-elevation-1-bordered::before,
body.sky-theme-modern.sky-theme-brand-base.sky-theme-mode-dark .sky-theme-border-container-default::before,
body.sky-theme-modern.sky-theme-brand-base.sky-theme-mode-dark .swatch::before {
	content: '';
	position: absolute;
	inset: 0;
	border-radius: inherit;
	padding: 1px;
	background: linear-gradient(
		to top,
		var(--bb-color-gray-800),
		var(--bb-color-gray-850)
	);
	-webkit-mask: linear-gradient(#000 0 0) content-box, linear-gradient(#000 0 0);
	-webkit-mask-composite: xor;
	mask: linear-gradient(#000 0 0) content-box, linear-gradient(#000 0 0);
	mask-composite: exclude;
	pointer-events: none;
}

/* Phase B – surface-relative experiment (do not ship)
   Mechanical model only: one fixed lift delta applied from immediate surface.
   No per-surface or per-component tuning. */
body.sky-theme-modern.sky-theme-brand-base.sky-theme-mode-dark {
	--local-exp-current-surface: var(--sky-color-background-page);
	--local-exp-input-lift-surface-weight: 84%;
	--local-exp-input-lift-white-weight: 16%;
}

/* Detect surface context from existing SKY UX structure/classes. */
body.sky-theme-modern.sky-theme-brand-base.sky-theme-mode-dark :where(
	.sky-box,
	.sky-theme-color-background-container-default,
	.sky-theme-background-container-default,
	[data-sky-surface='container-base']
) {
	--local-exp-current-surface: var(--sky-color-background-container-base);
}

